const cfg = $('Workflow Configuration').first().json;
const maxBusinesses = Number(cfg.maxBusinessesPerRun || 25);
const now = Date.now();
const upper = value => String(value || '').toUpperCase();
const isDue = row => !row.next_retry_at || Date.parse(row.next_retry_at) <= now;
const leaseExpired = row => !row.lease_until || Date.parse(row.lease_until) <= now;
const selectable = row => {
  const status = upper(row.pipeline_status || row.status);
  if (['SCRAPED', 'FAILED_RETRYABLE'].includes(status)) return true;
  return status === 'ENRICHING' && leaseExpired(row);
};
return $input.all()
  .map(item => item.json)
  .filter(row => Boolean(row.website))
  .filter(row => selectable(row))
  .filter(row => Number(row.attempt_count || 0) < Number(row.max_attempts || cfg.maxAttempts || 3))
  .filter(row => isDue(row) && leaseExpired(row))
  .sort((a, b) => {
    const aTime = a.last_checked_at ? Date.parse(a.last_checked_at) : 0;
    const bTime = b.last_checked_at ? Date.parse(b.last_checked_at) : 0;
    return aTime - bTime;
  })
  .slice(0, maxBusinesses)
  .map(row => ({ json: row }));

const cfg = $('Workflow Configuration').first().json;
const basePaths = ['', '/contact', '/about', '/team', '/locations'];
const normalize = (url = '') => String(url || '').replace(/\/$/, '');
const now = new Date();
const leaseUntil = new Date(now.getTime() + Number(cfg.leaseMinutes || 30) * 60 * 1000).toISOString();
const leaseOwner = 'enrichment:' + ($execution.id || Date.now());
const rows = [];
for (const [index, item] of $input.all().entries()) {
  const website = normalize(item.json.website);
  if (!website) continue;
  for (const path of basePaths) {
    rows.push({
      json: {
        ...item.json,
        pipeline_status: 'ENRICHING',
        status: 'ENRICHING',
        stage: 'enrichment',
        attempt_count: Number(item.json.attempt_count || 0) + 1,
        max_attempts: Number(item.json.max_attempts || cfg.maxAttempts || 3),
        lease_owner: leaseOwner,
        lease_until: leaseUntil,
        updated_at: now.toISOString(),
        fetch_url: website + path,
        page_label: path || '/',
      },
      pairedItem: { item: index },
    });
  }
}
return rows;

const fetchTargets = $('Build Fetch Targets').all();
return $input.all().map((item) => {
  const responseJson = item.json;
  const paired = item.pairedItem;
  const sourceIndex = Array.isArray(paired) ? paired[0]?.item : paired?.item;
  const source = fetchTargets[sourceIndex]?.json || {};
  const failed = Boolean(responseJson.error || responseJson.errorMessage || responseJson.statusCode >= 400);
  const html = failed ? '' : (typeof responseJson === 'string'
    ? responseJson
    : String(responseJson.body || responseJson.data || JSON.stringify(responseJson)));
  const emailMatches = Array.from(new Set((html.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/gi) || []).map(v => v.toLowerCase())));
  const instagramMatch = html.match(/https?:\/\/(?:www\.)?instagram\.com\/[^"'\s<]+/i);
  const facebookMatch = html.match(/https?:\/\/(?:www\.)?facebook\.com\/[^"'\s<]+/i);
  const hasContactForm = /<form[\s>][\s\S]{0,800}?(contact|book|appointment|consult)/i.test(html);
  return {
    json: {
      ...source,
      page_label: source.page_label || '',
      page_html: html.slice(0, 200000),
      page_failed: failed,
      page_error: failed ? String(responseJson.errorMessage || responseJson.message || responseJson.error || ('HTTP ' + (responseJson.statusCode || 'error'))) : '',
      emails_found: emailMatches,
      instagram_url: instagramMatch ? instagramMatch[0] : '',
      facebook_url: facebookMatch ? facebookMatch[0] : '',
      contact_form_present: hasContactForm,
    },
    pairedItem: paired,
  };
});

const items = $input.all().map(item => item.json);
const groups = new Map();
const qualifyText = value => /med spa|medical spa|aesthetic|cosmetic|injectable|dermal|laser|skin rejuvenation|botox/i.test(String(value || ''));
const retryAt = attempt => new Date(Date.now() + Math.min(360, 15 * Math.pow(4, Math.max(0, attempt - 1))) * 60 * 1000).toISOString();
for (const item of items) {
  const key = item.lead_id || item.raw_result_key;
  if (!groups.has(key)) {
    groups.set(key, {
      ...item,
      emails: new Set(),
      instagram_url: '',
      facebook_url: '',
      contact_page: '',
      contact_form_present: false,
      page_text: '',
      page_failures: [],
    });
  }
  const group = groups.get(key);
  for (const email of item.emails_found || []) group.emails.add(email);
  if (!group.instagram_url && item.instagram_url) group.instagram_url = item.instagram_url;
  if (!group.facebook_url && item.facebook_url) group.facebook_url = item.facebook_url;
  if (!group.contact_page && /\/contact$/i.test(item.fetch_url || '')) group.contact_page = item.fetch_url;
  group.contact_form_present = group.contact_form_present || Boolean(item.contact_form_present);
  group.page_text += ' ' + (item.page_html || '');
  if (item.page_failed) group.page_failures.push(item.page_error || 'fetch_failed');
}
const now = new Date().toISOString();
const rows = [];
for (const group of groups.values()) {
  const categoryHit = qualifyText(group.category);
  const siteHit = qualifyText(group.page_text);
  const keywordHit = qualifyText(group.keyword);
  const allPagesFailed = group.page_failures.length > 0 && !group.page_text.trim();
  const attempts = Number(group.attempt_count || 1);
  const maxAttempts = Number(group.max_attempts || 3);
  const qualified = categoryHit || siteHit || keywordHit;
  const failedTerminal = allPagesFailed && attempts >= maxAttempts;
  const pipelineStatus = allPagesFailed ? (failedTerminal ? 'FAILED_TERMINAL' : 'FAILED_RETRYABLE') : (qualified ? 'ENRICHED' : 'DISQUALIFIED');
  const qualificationStatus = qualified ? 'qualified' : (allPagesFailed ? 'unknown' : 'disqualified');
  const emails = Array.from(group.emails.values()).filter(email => !/noreply|no-reply|donotreply/i.test(email));
  rows.push({
    json: {
      lead_id: group.lead_id || group.raw_result_key || group.dedupe_key,
      dedupe_key: group.dedupe_key || group.lead_id,
      identity_strategy: group.identity_strategy || '',
      identity_key: group.identity_key || '',
      duplicate_of_lead_id: group.duplicate_of_lead_id || '',
      business_name: group.business_name,
      business_name_normalized: group.business_name_normalized || '',
      category: group.category,
      city: group.city,
      state: group.state,
      state_code: group.state_code || '',
      country: group.country || 'US',
      full_address: group.full_address,
      phone: group.phone,
      phone_e164: group.phone_e164 || '',
      website: group.website,
      domain: group.domain,
      email: emails[0] || '',
      contact_page: group.contact_page || '',
      instagram_url: group.instagram_url || '',
      facebook_url: group.facebook_url || '',
      google_maps_url: group.google_maps_url,
      rating: group.rating,
      review_count: group.review_count,
      matched_keywords: group.matched_keywords,
      primary_keyword: group.keyword,
      source_query_template: group.source_query_template,
      source_query_executed: group.source_query_executed,
      qualification_status: qualificationStatus,
      qualification_reason: qualified ? (categoryHit ? 'matched_google_category' : (siteHit ? 'matched_website_services' : 'matched_source_keyword')) : (allPagesFailed ? 'website_fetch_failed' : 'not_med_spa_match'),
      pipeline_status: pipelineStatus,
      status: pipelineStatus,
      stage: 'enrichment',
      attempt_count: attempts,
      max_attempts: maxAttempts,
      next_retry_at: pipelineStatus === 'FAILED_RETRYABLE' ? retryAt(attempts) : '',
      lease_owner: '',
      lease_until: '',
      first_seen_at: group.first_seen_at || now,
      last_seen_at: group.last_seen_at || now,
      last_checked_at: now,
      last_error_stage: allPagesFailed ? 'enrichment' : '',
      last_error_code: allPagesFailed ? 'WEBSITE_FETCH_FAILED' : '',
      last_error: allPagesFailed ? group.page_failures.join(' | ').slice(0, 1000) : '',
      ghl_sync_status: group.ghl_sync_status || (qualified ? 'pending' : 'skipped'),
      ghl_contact_id: group.ghl_contact_id || '',
      ghl_last_sync_at: group.ghl_last_sync_at || '',
      ghl_error: group.ghl_error || '',
      done_at: group.done_at || '',
      schema_version: group.schema_version || 'v1',
      notes: group.contact_form_present ? 'Contact form detected on site' : '',
    },
  });
}
return rows;

const now = new Date().toISOString();
return $input.all().map(item => ({
  json: {
    event_id: 'enrichment-' + (item.json.lead_id || item.json.dedupe_key) + '-' + Date.now(),
    lead_id: item.json.lead_id || item.json.dedupe_key || '',
    search_job_id: item.json.search_job_id || item.json.queue_key || '',
    workflow_name: 'med-spa-enrichment-qualifier',
    execution_id: String($execution.id || ''),
    from_status: 'SCRAPED',
    to_status: item.json.pipeline_status || item.json.status || '',
    stage: 'enrichment',
    message: item.json.qualification_reason || 'Enrichment completed',
    event_payload: JSON.stringify({ email: item.json.email, contact_page: item.json.contact_page, qualification_status: item.json.qualification_status }),
    created_at: now,
  }
}));

const now = new Date().toISOString();
return $input.all()
  .map(item => item.json)
  .filter(row => ['FAILED_RETRYABLE', 'FAILED_TERMINAL'].includes(String(row.pipeline_status || row.status || '').toUpperCase()))
  .map(row => ({
    json: {
      error_id: 'enrichment-' + (row.lead_id || row.dedupe_key || Date.now()) + '-' + Date.now(),
      workflow_name: 'med-spa-enrichment-qualifier',
      execution_id: String($execution.id || ''),
      record_type: 'lead',
      record_id: row.lead_id || row.dedupe_key || '',
      lead_id: row.lead_id || row.dedupe_key || '',
      search_job_id: row.search_job_id || row.queue_key || '',
      stage: 'enrichment',
      attempt_count: row.attempt_count || 0,
      error_code: row.last_error_code || 'ENRICHMENT_ERROR',
      error_message: row.last_error || '',
      raw_error_json: JSON.stringify(row),
      retryable: String(row.pipeline_status || row.status || '').toUpperCase() === 'FAILED_RETRYABLE' ? 'true' : 'false',
      next_retry_at: row.next_retry_at || '',
      created_at: now,
    }
  }));
